import numpy as np

def user_based_cf(ratings: np.ndarray, user: int, item: int, k: int = 3) -> float:
    target = ratings[user].astype(float)
    candidates = []
    for u in range(len(ratings)):
        if u == user or ratings[u, item] == 0:
            continue
        other = ratings[u].astype(float)
        denom = np.linalg.norm(target) * np.linalg.norm(other)
        if denom == 0:
            sim = 0.0
        else:
            sim = np.dot(target, other) / denom
        candidates.append((sim, float(ratings[u, item])))
    if not candidates:
        return 0.0
    candidates.sort(key=lambda x: -x[0])
    top = candidates[:k]
    sim_sum = sum(abs(s) for s, _ in top)
    if sim_sum == 0:
        return 0.0
    return sum(s * r for s, r in top) / sim_sum
